import{_ as e}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as i,c as a,af as o}from"./chunks/runtime-core.esm-bundler.B2oc1Rjn.js";const r="/img.png",p="/img_1.png",b=JSON.parse('{"title":"Выбор стека технологий (доступность и поддерживаемость)","description":"","frontmatter":{"title":"Выбор стека технологий (доступность и поддерживаемость)","date":"2022-12-24T00:00:00.000Z","permalink":"/stack-2","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2022-12-24-stack-2-maintainability-reliability"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Выбор стека технологий (доступность и поддерживаемость)"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2022-12-24-stack-2-maintainability-reliability"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Выбор стека технологий (доступность и поддерживаемость)"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Выбор стека технологий (доступность и поддерживаемость)\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2022-12-24-stack-2-maintainability-reliability\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2022-12-24\\"}"]]},"headers":[],"relativePath":"posts/2022-12-24-stack-2-maintainability-reliability.md","filePath":"posts/2022-12-24-stack-2-maintainability-reliability.md"}'),n={name:"posts/2022-12-24-stack-2-maintainability-reliability.md"};function l(s,t,c,h,g,m){return i(),a("div",null,[...t[0]||(t[0]=[o('<p>Это вторая статья в цикле &quot;Выбор стека технологий&quot;.</p><p><a href="/stack-1.html">1. Выбор стека технологий (введение и кейсы)</a></p><p>В первой статье мы определили содержание стека технологий. Это:</p><ul><li>хранилище данных</li><li>бэкенд-фреймворк</li><li>фронтенд-фреймворк</li><li>системы виртуализации/контейнеризации</li><li>DevOps (IaC, мониторинг, логгирование), например, ELK (Elasticsearch, Logstash, Kibana)</li></ul><hr><h2 id="доступность-reliability" tabindex="-1">Доступность (reliability) <a class="header-anchor" href="#доступность-reliability" aria-label="Permalink to &quot;Доступность (reliability)&quot;">​</a></h2><p>Доступность измеряется отношением общества количества запросов к количеству неответов.</p><p>Вернемся к кейсам и ранжируем их по требованиям к надежности:</p><p>EdTech - SLA 99.999% прописано в контракте (5 минут в год на обслуживание)</p><p>HR-Tech - business-critical, SLA 99.99%</p><p>PropTech - 2 часа offline в неделю, при том, что это PWA вполне допустимо.</p><p>FinTech - консоль SaaS будет использоваться раз в месяц, даже если пролежит неделю - не критично</p><p>Blog - мой блог лежал полгода и переезжал с домена на домен, самый менее критичный продукт с требованием к персистентности больше чем к доступности</p><p>По стеку что выбрано в результате и на ходу:</p><p>EdTech - Postgres, Java 17 Spring Boot, Low-Code, Next.js (SSG+Nginx), Tailwind, отдельный человек-SRE (Docker, minio, Yandex Cloud Kubernetes) - с появлением Java 19, пророчу Java долгую, но сложную жизнь</p><p>HR-Tech - Postgres, Java microservices, Angular 1X, Kafka, Shared SRE (0.3 FTE)</p><p>PropTech - MongoDB, Redis, Nest.js, React, no devops - MongoDB падает на 200 пользователях, переписать на Postgres - полгода работы пары человек минимум</p><p>FinTech - .Net Core (потому что Azure AD), Angular</p><p>Blog - GitHub Pages, VuePress, Markdown</p><p>По факту, как ни смешно, самым надежным оказался блог на GitHub Pages. Простота = надежность.</p><p>На других проектах DevOps-практика подкачала, деплои были большей частью ручные, а релизы - нестабильные.</p><p>Вывод - доступность приложения целиком и полностью зависит от Ops и инфраструктуры. Это база, которая закладывается на старте проекта.</p><p>Поэтому если доступность одно из требований, уже при инициализации проекта должны быть настроены бэкапы и восстановление, мониторинг, система оповещений об инцидентах, пайплайн поставок, тестовые стенды и простейшие автотесты.</p><p>Здесь мой выбор пал на GitLab, Jenkins и AWS. Ввиду отсутствия альтернатив. В случае российских проектов, Yandex Cloud достаточно production-ready с отзывчивой поддержкой.</p><h2 id="поддерживаемость" tabindex="-1">Поддерживаемость <a class="header-anchor" href="#поддерживаемость" aria-label="Permalink to &quot;Поддерживаемость&quot;">​</a></h2><p>По стандарту ISO/IEC 25010 поддерживаемость - набор атрибутов, содержащих необходимые усилия для внесения изменений.</p><p>Чтобы что-то изменить, это нужно - проанализировать, изменить, отладить и протестировать.</p><img src="'+r+'" alt="ISO/IEC 25010 — атрибуты поддерживаемости" width="1213" height="481" style="max-width:100%;height:auto;"><p>Как человек, проведший огромное количество времени за реверс-инженерией legacy-кода, я ставлю этот атрибут вторым параметром в уравнение поиска идеального стека.</p><p>Java 19 догнал в развитии Elixir/Erlang спустя 30 лет этой гонки.</p><p>Тем не менее, поддерживаемым код паралельных процессов и всего остального на Java назвать сложно.</p><p>Недаром в последнем опросе пользовательских предпочтений StackOverflow, Elixir на втором месте.</p><p>Если бы проекты можно было писать без оглядки на рынок, я бы взял для бэкенда Elixir. Ибо любой разработчик поймет код который на нем написан. И сможет писать на нем уже через пару недель. А вот с Java не так.</p><p>Elixir это не только синтаксис, сколько среда выполнения, обратите внимание на табличку ниже из книги Elixir in Action: <img src="'+p+'" alt="Среда выполнения Elixir/Erlang (Elixir in Action)" width="992" height="352" style="max-width:100%;height:auto;"></p><p>Несмотря на то, что Elixir медленнее компилируемых языков, в плане реализации высокодоступных систем ему нет равных.</p><p>Поэтому если бы я выбирал стек технологий снова, он был бы таким:</p><p>EdTech - Postgres, Phoenix LiveView, Tailwind</p><p>HR-Tech - Postgres, Phoenix LiveView, Kafka</p><p>PropTech - просто убрал бы пересчет аналитики в транзакции, JS-стек стартапу подошел хорошо</p><p>FinTech - .Net Core (потому что Azure AD), Angular - по-другому никак</p><p>Blog - GitHub Pages, VuePress, Markdown - идеально</p>',41)])])}const y=e(n,[["render",l]]);export{b as __pageData,y as default};
